module thermal_sensor_calibration(  
    input [9:0] calibration_input,  
    output reg [9:0] temperature_out  
);  
    always @(*) begin  
        if (calibration_input < 10'd100)  
            temperature_out = calibration_input;  
        else  
            temperature_out = calibration_input - 10'd10;  
    end  
endmodule
